s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

DYNAMODB_TABLE = os.environ.get('DYNAMODB_TABLE', 'microservices-data')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
SQS_QUEUE_URL = os.environ.get('SQS_QUEUE_URL', '')
S3_BUCKET = os.environ.get('S3_BUCKET', 'microservices-storage')


def lambda_handler(event, context):
    try:
        operation = event.get('operation', 'process')
        
        if operation == 'process':
            return process_request(event)
        elif operation == 's3_operation':
            return handle_s3_operation(event)
        elif operation == 'dynamodb_operation':
            return handle_dynamodb_operation(event)
        elif operation == 'sns_operation':
            return handle_sns_operation(event)
        elif operation == 'sqs_operation':
            return handle_sqs_operation(event)
        else:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Unknown operation'})
            }
    
    except Exception as e:
        print(f"Error processing request: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }


def process_request(event):
    data = event.get('data', {})
    
    table = dynamodb.Table(DYNAMODB_TABLE)
    item = {
        'id': event.get('id', str(datetime.now().timestamp())),
        'timestamp': datetime.now().isoformat(),
        'data': json.dumps(data),
        'status': 'processed'
    }
    
    table.put_item(Item=item)
    
    if SNS_TOPIC_ARN:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps(item),
            Subject='Microservice Processing Complete'
        )
    
    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'Request processed successfully',
            'item': item
        })
    }


def handle_s3_operation(event):
    operation_type = event.get('s3_operation_type', 'put')
    key = event.get('key', 'default.json')
    
    if operation_type == 'put':
        data = event.get('data', {})
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=key,
            Body=json.dumps(data),
            ContentType='application/json'
        )
        return {
            'statusCode': 200,
            'body': json.dumps({'message': f'Object {key} uploaded to S3'})
        }
    
    elif operation_type == 'get':
        response = s3_client.get_object(Bucket=S3_BUCKET, Key=key)
        data = json.loads(response['Body'].read())
        return {
            'statusCode': 200,
            'body': json.dumps({'data': data})
        }
    
    elif operation_type == 'delete':
        s3_client.delete_object(Bucket=S3_BUCKET, Key=key)
        return {
            'statusCode': 200,
            'body': json.dumps({'message': f'Object {key} deleted from S3'})
        }
    
    return {
        'statusCode': 400,
        'body': json.dumps({'error': 'Invalid S3 operation type'})
    }


def handle_dynamodb_operation(event):
    operation_type = event.get('dynamodb_operation_type', 'put')
    table = dynamodb.Table(DYNAMODB_TABLE)
    
    if operation_type == 'put':
        item = event.get('item', {})
        table.put_item(Item=item)
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Item added to DynamoDB'})
        }
    
    elif operation_type == 'get':
        key = event.get('key', {})
        response = table.get_item(Key=key)
        return {
            'statusCode': 200,
            'body': json.dumps({'item': response.get('Item')})
        }
    
    elif operation_type == 'query':
        key_condition = event.get('key_condition', {})
        response = table.query(KeyConditionExpression=key_condition)
        return {
            'statusCode': 200,
            'body': json.dumps({'items': response.get('Items', [])})
        }
    
    elif operation_type == 'delete':
        key = event.get('key', {})
        table.delete_item(Key=key)
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Item deleted from DynamoDB'})
        }
    
    return {
        'statusCode': 400,
        'body': json.dumps({'error': 'Invalid DynamoDB operation type'})
    }


def handle_sns_operation(event):
    message = event.get('message', '')
    subject = event.get('subject', 'Microservice Notification')
    
    if not SNS_TOPIC_ARN:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'SNS Topic ARN not configured'})
        }
    
    response = sns_client.publish(
        TopicArn=SNS_TOPIC_ARN,
        Message=message,
        Subject=subject
    )
    
    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'SNS message published',
            'messageId': response['MessageId']
        })
    }


def handle_sqs_operation(event):
    operation_type = event.get('sqs_operation_type', 'send')
    
    if not SQS_QUEUE_URL:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'SQS Queue URL not configured'})
        }
    
    if operation_type == 'send':
        message = event.get('message', {})
        response = sqs_client.send_message(
            QueueUrl=SQS_QUEUE_URL,
            MessageBody=json.dumps(message)
        )
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message sent to SQS',
                'messageId': response['MessageId']
            })
        }
    
    elif operation_type == 'receive':
        response = sqs_client.receive_message(
            QueueUrl=SQS_QUEUE_URL,
            MaxNumberOfMessages=event.get('max_messages', 10)
        )
        messages = response.get('Messages', [])
        return {
            'statusCode': 200,
            'body': json.dumps({'messages': messages})
        }
    
    elif operation_type == 'delete':
        receipt_handle = event.get('receipt_handle', '')
        sqs_client.delete_message(
            QueueUrl=SQS_QUEUE_URL,
            ReceiptHandle=receipt_handle
        )
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Message deleted from SQS'})
        }
    
    return {
        'statusCode': 400,
        'body': json.dumps({'error': 'Invalid SQS operation type'})
    }